  & .monaco-keybinding-key { color: var(--vscode-editorActionList-focusForeground); }
}
}

.monaco-editor {
  & .scroll-editor-on-middle-click-dot {
  cursor: all-scroll; position: absolute; z-index: 1; background-color: var(--vscode-editor-foreground, white); border: 1px solid var(--vscode-editor-background, black); opacity: 0.5; width: 5px; height: 5px; border-radius: 50%; transform: translate(-50%, -50%);
  &.hidden { display: none; }
}
  &.scroll-editor-on-middle-click-editor * { cursor: all-scroll; }
}

.monaco-editor {
  & .editorPlaceholder { top: 0px; position: absolute; overflow: hidden; text-overflow: ellipsis; text-wrap: nowrap; pointer-events: none; color: var(--vscode-editor-placeholder-foreground); }
}

.floating-menu-overlay-widget {
  padding: 0px; color: var(--vscode-button-foreground); background-color: var(--vscode-button-background); border-radius: 2px; border: 1px solid var(--vscode-contrastBorder); display: flex; align-items: center; z-index: 10; box-shadow: 0 2px 8px var(--vscode-widget-shadow); overflow: hidden;
  & .action-item > .action-label { padding: 5px; font-size: 12px; border-radius: 2px; }
  & .action-item > .action-label.codicon { color: var(--vscode-button-foreground); }
  & .action-item > .action-label.codicon:not(.separator) { padding-top: 6px; padding-bottom: 6px; }
  & .action-item:first-child > .action-label { padding-left: 7px; }
  & .action-item:last-child > .action-label { padding-right: 7px; }
  & .action-item .action-label.separator { background-color: var(--vscode-menu-separatorBackground); }
}

.LiveLogBadge { position: absolute; top: 10px; right: 14px; z-index: 5; display: inline-flex; align-items: center; gap: 6px; padding: 2px 8px; border-radius: 10px; font-size: 10px; font-weight: 600; letter-spacing: 0.08em; pointer-events: none; user-select: none; color: rgb(230, 230, 230); background: rgba(20, 20, 20, 0.72); border: 1px solid rgba(255, 255, 255, 0.12); backdrop-filter: blur(2px); }.LiveLogBadgeDot { width: 7px; height: 7px; border-radius: 50%; background: rgb(138, 138, 138); }.LiveLogBadge[data-tone="live"] .LiveLogBadgeDot { background: rgb(21, 179, 113); }.LiveLogBadge[data-tone="connecting"] .LiveLogBadgeDot { background: rgb(217, 163, 0); }.LiveLogBadge[data-tone="error"] { color: rgb(255, 115, 115); }.LiveLogBadge[data-tone="error"] .LiveLogBadgeDot { background: rgb(219, 55, 55); }.LiveLogBadge[data-tone="snapshot"] .LiveLogBadgeDot { background: rgb(92, 112, 128); }.LiveLogBadge[data-pulsing="true"] .LiveLogBadgeDot { animation: 1.4s ease-in-out 0s infinite normal none running liveLogPulse; }@keyframes liveLogPulse { 
  0%, 100% { opacity: 1; }
  50% { opacity: 0.45; }
}
